#include <stdio.h>
#include <string.h>
#include <stdbool.h>

static void trim_newline(char *s) {
    size_t len = strlen(s);
    if (len && s[len-1] == '\n') s[len-1] = '\0';
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    while (T--) {
        char str1[100005];
        char str2[100005];
        if (!fgets(str1, sizeof(str1), stdin)) break;
        if (!fgets(str2, sizeof(str2), stdin)) break;
        trim_newline(str1);
        trim_newline(str2);
        bool present[256] = {false};
        for (size_t i = 0; str2[i]; ++i) {
            present[(unsigned char)str2[i]] = true;
        }
        long long ans = 0;
        for (size_t i = 0; str1[i]; ++i) {
            if (present[(unsigned char)str1[i]]) ++ans;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

