const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').split('\n').map(l => l.replace(/\r$/,''));
let idx = 0;
const T = parseInt(lines[idx++].trim(), 10);
let output = [];
for (let tc = 0; tc < T; ++tc) {
  const str1 = lines[idx++] ?? '';
  const str2 = lines[idx++] ?? '';
  const present = new Array(256).fill(false);
  for (let i = 0; i < str2.length; ++i) {
    present[str2.charCodeAt(i)] = true;
  }
  let ans = 0;
  for (let i = 0; i < str1.length; ++i) {
    if (present[str1.charCodeAt(i)]) ++ans;
  }
  output.push(String(ans));
}
